package org.iets3.core.expr.typetags.physunits.behavior;

/*Generated by MPS */

import org.jetbrains.mps.openapi.model.SNode;
import jetbrains.mps.classloading.ClassLoaderManager;
import jetbrains.mps.typesystem.inference.TypeCheckingContext;
import jetbrains.mps.newTypesystem.context.IncrementalTypecheckingContext;
import jetbrains.mps.typesystem.inference.TypeChecker;

public class TypeHelper {

  public static SNode computeType(SNode expr) {
    // deprecated getInstance is necessary to ensure compatibility
    // with the command-line generator execution (MpsEnvironment)
    ClassLoaderManager classLoaderManager = ClassLoaderManager.getInstance();
    TypeCheckingContext typeChecking = new IncrementalTypecheckingContext(expr, TypeChecker.getInstance().getTypeCheckerHelper(), classLoaderManager);

    // execute typesystem to check the expression's type
    typeChecking.checkIfNotChecked(expr, false);

    // get the type for the expression
    SNode result = typeChecking.typeOf(expr);

    // clean-up
    typeChecking.dispose();

    return result;
  }
}
